// ---------------------------------------------------------------------------
// SEED FUNCTION
// ---------------------------------------------------------------------------
async function seedRecipes() {
  console.log('\n🌱 Starting VEG recipe seed (v4.1)...');
  console.log('📦 Step 1: Creating missing food items...\n');

  const nameToKey = (s: string) =>
    s
      .toUpperCase()
      .replace(/[^A-Z0-9]/g, '_')
      .replace(/_+/g, '_')
      .replace(/^_+|_+$/g, '');

  for (const item of MISSING_FOOD_ITEMS) {
    const key = nameToKey(item.name);
    if (!key) {
      console.log(`⚠️  No key for: ${item.name}`);
      continue;
    }
    const existing = await prisma.foodItem.findFirst({ where: { name: item.name } });
    if (existing) {
      NEW_FI[key] = existing.id;
      console.log(`⏭️  Exists: ${item.name} → ${existing.id}`);
      continue;
    }
    const created = await prisma.foodItem.create({
      data: {
        name: item.name,
        category: item.category,
        per100Calories: item.per100Calories,
        per100Protein: item.per100Protein,
        per100Carbs: item.per100Carbs,
        per100Fat: item.per100Fat,
        per100Fiber: item.per100Fiber,
        isCustom: false,
      },
    });
    NEW_FI[key] = created.id;
    console.log(`✅ Created: ${item.name} → ${created.id}`);
  }

  console.log(`\n📋 Step 2: Seeding ${RECIPES.length} recipes...\n`);
  let created = 0,
    skipped = 0;

  for (const def of RECIPES) {
    const existing = await prisma.recipe.findUnique({ where: { slug: def.recipe.slug } });
    if (existing) {
      console.log(`⏭️  Exists: ${def.recipe.name}`);
      skipped++;
      continue;
    }

    // Strip fields not present in the Prisma Recipe model (platingSummary, glycaemicIndex not in schema)
    const { platingSummary: _p, glycaemicIndex: _g, ...recipeData } = def.recipe;
    const recipe = await prisma.recipe.create({ data: recipeData });
    let errs = 0;

    for (const ing of def.ingredients) {
      const id = getFoodItemId(ing.foodItemKey);
      if (!id) {
        console.log(`  ⚠️  Missing key: ${ing.foodItemKey}`);
        errs++;
        continue;
      }
      await prisma.recipeIngredient.create({
        data: {
          recipeId: recipe.id,
          foodItemId: id,
          quantityGrams: ing.quantityGrams,
          cookedWeightFactor: ing.cookedWeightFactor,
          prepNote: ing.prepNote ?? null,
          isOptional: ing.isOptional,
          orderInRecipe: ing.orderInRecipe,
        },
      });
    }

    for (const step of def.steps) {
      await prisma.recipeStep.create({
        data: {
          recipeId: recipe.id,
          stepNumber: step.stepNumber,
          title: step.title,
          instruction: step.instruction,
          durationMins: step.durationMins ?? null,
          temperatureC: step.temperatureC ?? null,
          technique: step.technique ?? null,
          kitchenNote: step.kitchenNote ?? null,
          imageUrl: null,
        },
      });
    }

    const status = errs > 0 ? `⚠️  (${errs} missing keys)` : '✅';
    console.log(
      `${status} ${def.recipe.cuisineType} | ${def.recipe.mealType} | ${def.recipe.name} (${def.ingredients.length} ing, ${def.steps.length} steps)`,
    );
    created++;
  }

  console.log('\n─────────────────────────────────────────────────');
  console.log(`✅ Recipes created : ${created}`);
  console.log(`⏭️  Recipes skipped : ${skipped}`);
  console.log(`📋 Total           : ${RECIPES.length}`);
  console.log('─────────────────────────────────────────────────');
  console.log('🎉 balanced VEG seed complete! (generated by FitFuel Seed Generator v4.1)');
}

seedRecipes()
  .catch((e) => {
    console.error('💥 Seed failed:', e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
    pool.end();
  });